pub fn write_if_changed(&self) -> Result<(), LockfileWriteError> {
  if self.skip_write {
    return Ok(());
  }

  self
    .error_if_changed()
    .map_err(LockfileWriteError::Changed)?;
  let mut lockfile = self.lockfile.lock();
  let Some(bytes) = lockfile.resolve_write_bytes() else {
    return Ok(()); // nothing to do
  };
  // If the lockfile path is a symlink, resolve it to its target so the
  // atomic write below replaces the target file rather than clobbering the
  // symlink with a freshly created regular file. This matches how the
  // deno.json/package.json writes follow symlinks (they write in place).
  let write_path = if self.sys.fs_is_symlink_no_err(&lockfile.filename) {
    self
      .sys
      .fs_canonicalize(&lockfile.filename)
      .unwrap_or_else(|_| lockfile.filename.clone())
  } else {
    lockfile.filename.clone()
  };
  // do an atomic write to reduce the chance of multiple deno
  // processes corrupting the file
  const CACHE_PERM: u32 = 0o644;
  atomic_write_file_with_retries(&self.sys, &write_path, &bytes, CACHE_PERM)
    .map_err(LockfileWriteError::Io)?;
  lockfile.has_content_changed = false;
  Ok(())
}

fn split(self) -> (Self, Option<Self>) {
    if self.tail < 2 {
        return (Self { tail: 0, ..self }, None);
    }

    // Look forward for the separator, and failing that look backward.
    let mid = self.tail / 2;
    let index = match self.slice.find(self.pred, mid, self.tail) {
        Some(i) => Some(mid + i),
        None => self.slice.rfind(self.pred, mid + 1),
    };

    if let Some(index) = index {
        let (left, right) = self.slice.split(index);

        let (left_tail, right_tail) = if index <= mid {
            // If we scanned backwards to find the separator, everything in
            // the right side is exhausted, with no separators left to find.
            (index, 0)
        } else {
            (mid + 1, self.tail - index)
        };

        // Create the left split before the separator.
        let left = Self {
            slice: left,
            tail: left_tail,
            ..self
        };

        // Create the right split following the separator.
        let right = Self {
            slice: right,
            tail: right_tail,
            ..self
        };

        (left, Some(right))
    } else {
        // The search is exhausted, no more separators...
        (Self { tail: 0, ..self }, None)
    }
}

async fn download(&self, pkg: PackageId, checksum: &str) -> CargoResult<MaybeLock> {
    // Note that the usage of `into_path_unlocked` here is because the local
    // crate files here never change in that we're not the one writing them,
    // so it's not our responsibility to synchronize access to them.
    let path = self.root.join(&pkg.tarball_name()).into_path_unlocked();
    let mut crate_file = paths::open(&path)?;

    // If we've already got an unpacked version of this crate, then skip the
    // checksum below as it is in theory already verified.
    let dst = path.file_stem().unwrap();
    if self.src_path.join(dst).into_path_unlocked().exists() {
        return Ok(MaybeLock::Ready(crate_file));
    }

    if !self.quiet {
        self.gctx.shell().status("Unpacking", pkg)?;
    }

    // We don't actually need to download anything per-se, we just need to
    // verify the checksum matches the .crate file itself.
    let actual = Sha256::new().update_file(&crate_file)?.finish_hex();
    if actual != checksum {
        anyhow::bail!("failed to verify the checksum of `{}`", pkg)
    }

    crate_file.seek(SeekFrom::Start(0))?;

    Ok(MaybeLock::Ready(crate_file))
}

fn compute_drop_live_points_for(&mut self, local: Local) {
    debug!("compute_drop_live_points_for(local={:?})", local);

    let Some(mpi) = self.cx.move_data.rev_lookup.find_local(local) else { return };
    debug!("compute_drop_live_points_for: mpi = {:?}", mpi);

    // Find the drops where `local` is initialized.
    for drop_point in self.cx.local_use_map.drops(local) {
        let location = self.cx.location_map.to_location(drop_point);
        debug_assert_eq!(self.cx.body().terminator_loc(location.block), location,);

        if self.cx.initialized_at_terminator(location.block, mpi)
            && self.drop_live_at.insert(drop_point)
        {
            self.drop_locations.push(location);
            self.stack.push(drop_point);
        }
    }

    debug!("compute_drop_live_points_for: drop_locations={:?}", self.drop_locations);

    // Reverse DFS. But for drops, we do it a bit differently.
    // The stack only ever stores *terminators of blocks*. Within
    // a block, we walk back the statements in an inner loop.
    while let Some(term_point) = self.stack.pop() {
        self.compute_drop_live_points_for_block(mpi, term_point);
    }
}

pub fn insert_presorted(
    &mut self,
    // We require `TrustedLen` to ensure that the `splice` below is actually efficient.
    mut elements: impl Iterator<Item = (K, V)> + DoubleEndedIterator + TrustedLen,
) {
    let Some(first) = elements.next() else {
        return;
    };

    let start_index = self.lookup_index_for(&first.0);

    let elements = match start_index {
        Ok(index) => {
            self.data[index] = first; // overwrite first element
            elements.chain(None) // insert the rest below
        }
        Err(index) => {
            let last = elements.next_back();
            if index == self.data.len()
                || last.as_ref().is_none_or(|l| l.0 < self.data[index].0)
            {
                // We can copy the whole range without having to mix with
                // existing elements.
                self.data
                    .splice(index..index, std::iter::once(first).chain(elements).chain(last));
                return;
            }

            self.data.insert(index, first);
            elements.chain(last) // insert the rest below
        }
    };

    // Insert the rest. This is super inefficicent since each insertion copies the entire tail.
    for (k, v) in elements {
        self.insert(k, v);
    }
}

pub(crate) fn concat(self, other: Self) -> Self {
    if self.start == self.accept {
        return other;
    } else if other.start == other.accept {
        return self;
    }

    let start = self.start;
    let accept = other.accept;

    let mut transitions: Map<State, Transitions<R, T>> = self.transitions;

    for (source, transition) in other.transitions {
        let fix_state = |state| if state == other.start { self.accept } else { state };
        let byte_transitions = transition.byte_transitions.map_states(&fix_state);
        let ref_transitions = transition
            .ref_transitions
            .into_iter()
            .map(|(r, state)| (r, fix_state(state)))
            .collect();

        let old = transitions
            .insert(fix_state(source), Transitions { byte_transitions, ref_transitions });
        assert!(old.is_none());
    }

    Self { transitions, start, accept }
}

pub(crate) fn set_precision<T>() -> FPUControlWord {
    let mut cw = 0_u16;

    // Compute the value for the Precision Control field that is appropriate for `T`.
    let cw_precision = match size_of::<T>() {
        4 => 0x0000, // 32 bits
        8 => 0x0200, // 64 bits
        _ => 0x0300, // default, 80 bits
    };

    // Get the original value of the control word to restore it later, when the
    // `FPUControlWord` structure is dropped
    // SAFETY: the `fnstcw` instruction has been audited to be able to work correctly with
    // any `u16`
    unsafe {
        asm!(
            "fnstcw word ptr [{}]",
            in(reg) &mut cw,
            options(nostack),
        )
    }

    // Set the control word to the desired precision. This is achieved by masking away the old
    // precision (bits 8 and 9, 0x300) and replacing it with the precision flag computed above.
    set_cw((cw & 0xFCFF) | cw_precision);

    FPUControlWord(cw)
}

pub(crate) fn try_select(&mut self) -> Option<Entry> {
    if self.selectors.is_empty() {
        None
    } else {
        let thread_id = current_thread_id();

        self.selectors
            .iter()
            .position(|selector| {
                // Does the entry belong to a different thread?
                selector.cx.thread_id() != thread_id
                    && selector // Try selecting this operation.
                        .cx
                        .try_select(Selected::Operation(selector.oper))
                        .is_ok()
                    && {
                        // Provide the packet.
                        selector.cx.store_packet(selector.packet);
                        // Wake the thread up.
                        selector.cx.unpark();
                        true
                    }
            })
            // Remove the entry from the queue to keep it clean and improve
            // performance.
            .map(|pos| self.selectors.remove(pos))
    }
}

fn copy_to(&mut self, to: &mut (impl Write + ?Sized)) -> Result<u64> {
    let mut len = 0;

    loop {
        // Hack: this relies on `impl Read for BufReader` always calling fill_buf
        // if the buffer is empty, even for empty slices.
        // It can't be called directly here since specialization prevents us
        // from adding I: Read
        match self.read(&mut []) {
            Ok(_) => {}
            Err(e) if e.is_interrupted() => continue,
            Err(e) => return Err(e),
        }
        let buf = self.buffer();
        if self.buffer().len() == 0 {
            return Ok(len);
        }

        // In case the writer side is a BufWriter then its write_all
        // implements an optimization that passes through large
        // buffers to the underlying writer. That code path is #[cold]
        // but we're still avoiding redundant memcopies when doing
        // a copy between buffered inputs and outputs.
        to.write_all(buf)?;
        len += buf.len() as u64;
        self.discard_buffer();
    }
}

pub(crate) fn turn_into_const_value<'tcx>(
    tcx: TyCtxt<'tcx>,
    constant: ConstAlloc<'tcx>,
    key: ty::PseudoCanonicalInput<'tcx, GlobalId<'tcx>>,
) -> ConstValue {
    let cid = key.value;
    let def_id = cid.instance.def.def_id();
    let is_static = tcx.is_static(def_id);
    // This is just accessing an already computed constant, so no need to check alignment here.
    let ecx = mk_eval_cx_to_read_const_val(
        tcx,
        tcx.def_span(key.value.instance.def_id()),
        key.typing_env,
        CanAccessMutGlobal::from(is_static),
    );

    let mplace = ecx.raw_const_to_mplace(constant).expect(
        "can only fail if layout computation failed, \
        which should have given a good error before ever invoking this function",
    );
    assert!(
        !is_static || cid.promoted.is_some(),
        "the `eval_to_const_value_raw` query should not be used for statics, use `eval_to_allocation` instead"
    );

    // Turn this into a proper constant.
    op_to_const(&ecx, &mplace.into(), /* for diagnostics */ false)
}

pub(crate) fn render_struct_pat(
    ctx: RenderContext<'_, '_>,
    pattern_ctx: &PatternContext,
    strukt: hir::Struct,
    local_name: Option<Name>,
) -> Option<CompletionItem> {
    let _p = tracing::info_span!("render_struct_pat").entered();

    let fields = strukt.fields(ctx.db());
    let (visible_fields, fields_omitted) = visible_fields(ctx.completion, &fields, strukt)?;

    if visible_fields.is_empty() {
        // Matching a struct without matching its fields is pointless, unlike matching a Variant without its fields
        return None;
    }

    let name = local_name.unwrap_or_else(|| strukt.name(ctx.db()));
    let (name, escaped_name) =
        (name.as_str(), name.display(ctx.db(), ctx.completion.edition).to_smolstr());
    let kind = strukt.kind(ctx.db());
    let label = format_literal_label(name, kind, ctx.snippet_cap());
    let lookup = format_literal_lookup(name, kind);
    let pat = render_pat(&ctx, pattern_ctx, &escaped_name, kind, &visible_fields, fields_omitted)?;

    let db = ctx.db();

    Some(build_completion(ctx, label, lookup, pat, strukt, strukt.ty(db), false))
}

fn canonicalize_parent(mut path: PathBuf) -> Option<PathBuf> {
  let mut failed_components = None;

  loop {
    if let Ok(path) = path.canonicalize() {
      break Some(if let Some(p) = failed_components {
        path.join(p)
      } else {
        path
      });
    }

    // grap the last component of the path
    if let Some(mut last) = path.iter().next_back().map(PathBuf::from) {
      // remove the last component of the path so the next iteration checks its parent
      // if there is no more parent components, we failed to canonicalize
      if !path.pop() {
        break None;
      }

      // append the already checked path to the last component
      // to construct `<last>/<checked_path>` and saved it for next iteration
      if let Some(failed_components) = &failed_components {
        last.push(failed_components);
      }
      failed_components.replace(last);
    } else {
      break None;
    }
  }
}

fn is_maybe_closed(&self, tx: &Tx<T>, slot_index: usize) -> bool {
    let start_index = block::start_index(slot_index);

    let tail = tx.block_tail.load(Acquire);
    // SAFETY: Only the receiver frees blocks, so since we are the receiver, this will not be
    // freed right now.
    let tail_ref = unsafe { &*tail };
    if tail_ref.is_at_index(start_index) {
        return !tail_ref.has_value(slot_index);
    }

    // This method is optimized for checking whether the last value is present, so most of the
    // time it is in `block_tail`. However, this isn't always the case since it's possible
    // that the list was grown with an empty block, in which case `block_tail` points one block
    // too far. To handle this case, we walk the list from the head.
    let mut block_ptr = Some(self.head);

    while let Some(block) = block_ptr {
        // SAFETY: Only the receiver frees blocks, so since we are the receiver, this will not
        // be freed right now.
        let block_ref = unsafe { block.as_ref() };
        if block_ref.is_at_index(start_index) {
            return !block_ref.has_value(slot_index);
        }
        block_ptr = block_ref.load_next(Acquire);
    }
    true
}

pub(crate) fn decrease_handle_refcount(node: &Arc<TreeNode>) {
    let num_handles = {
        let mut locked_node = node.inner.lock().unwrap();
        locked_node.num_handles -= 1;
        locked_node.num_handles
    };

    if num_handles == 0 {
        with_locked_node_and_parent(node, |mut node, parent| {
            // Remove the node from the tree
            match parent {
                Some(mut parent) => {
                    // As we want to remove ourselves from the tree,
                    // we have to move the children to the parent, so that
                    // they still receive the cancellation event without us.
                    // Moving them does not violate invariant #1.
                    move_children_to_parent(&mut node, &mut parent);

                    // Remove the node from the parent
                    remove_child(&mut parent, node);
                }
                None => {
                    // Due to invariant #1, we can assume that our
                    // children can no longer be cancelled through us.
                    // (as we now have neither a parent nor handles)
                    // Therefore we can disconnect them.
                    disconnect_children(&mut node);
                }
            }
        });
    }
}

pub(crate) unsafe fn register_op(&self, entry: Entry, waker: Waker) -> io::Result<usize> {
    assert!(self.uring_probe.initialized());

    // Uring is initialized.

    let mut guard = self.get_uring().lock();
    let ctx = &mut *guard;
    let index = ctx.ops.insert(Lifecycle::Waiting(waker));
    let entry = entry.user_data(index as u64);

    let submit_or_remove = |ctx: &mut UringContext| -> io::Result<()> {
        if let Err(e) = ctx.submit() {
            // Submission failed, remove the entry from the slab and return the error
            ctx.remove_op(index);
            return Err(e);
        }
        Ok(())
    };

    // SAFETY: entry is valid for the entire duration of the operation
    while unsafe { ctx.ring_mut().submission().push(&entry).is_err() } {
        // If the submission queue is full, flush it to the kernel
        submit_or_remove(ctx)?;
    }

    // Ensure that the completion queue is not full before submitting the entry.
    while ctx.ring_mut().completion().is_full() {
        ctx.dispatch_completions();
    }

    // Note: For now, we submit the entry immediately without utilizing batching.
    submit_or_remove(ctx)?;

    Ok(index)
}

fn new_service(&self, _: ()) -> Self::Future {
    // construct all services factory future with its resource def and guards.
    let factory_fut = join_all(self.services.iter().map(|(path, factory, guards)| {
        let path = path.clone();
        let guards = guards.borrow_mut().take().unwrap_or_default();
        let factory_fut = factory.new_service(());
        async move {
            factory_fut
                .await
                .map(move |service| (path, guards, service))
        }
    }));

    // construct default service factory future
    let default_fut = self.default.new_service(());

    Box::pin(async move {
        let default = default_fut.await?;

        // build router from the factory future result.
        let router = factory_fut
            .await
            .into_iter()
            .collect::<Result<Vec<_>, _>>()?
            .drain(..)
            .fold(Router::build(), |mut router, (path, guards, service)| {
                router.push(path, service, guards);
                router
            })
            .finish();

        Ok(AppRouting { router, default })
    })
}

async fn test_pool_keep_alive() {
    let generated = Rc::new(Cell::new(0));
    let generated_clone = generated.clone();

    let connector = TestPoolConnector { generated };

    let config = ConnectorConfig {
        conn_keep_alive: Duration::from_secs(1),
        ..Default::default()
    };

    let pool = super::ConnectionPool::new(connector, config);

    let req = Connect {
        uri: Uri::from_static("http://localhost"),
        addr: None,
    };

    let conn = pool.call(req.clone()).await.unwrap();
    assert_eq!(1, generated_clone.get());
    release(conn);

    let conn = pool.call(req.clone()).await.unwrap();
    assert_eq!(1, generated_clone.get());
    release(conn);

    actix_rt::time::sleep(Duration::from_millis(1500)).await;
    actix_rt::task::yield_now().await;

    let conn = pool.call(req).await.unwrap();
    // Note: spawned recycle connection is not ran yet.
    // This is tokio current thread runtime specific behavior.
    assert_eq!(2, generated_clone.get());

    // yield task so the old connection is properly dropped.
    actix_rt::task::yield_now().await;
    assert_eq!(1, generated_clone.get());

    release(conn);
}

