fn push_internal(
    &self,
    onto: Shared<'_, Node<T>>,
    new: Shared<'_, Node<T>>,
    guard: &Guard,
) -> bool {
    // is `onto` the actual tail?
    let o = unsafe { onto.deref() };
    let next = o.next.load(Acquire, guard);
    if unsafe { next.as_ref().is_some() } {
        // if not, try to "help" by moving the tail pointer forward
        let _ = self
            .tail
            .compare_exchange(onto, next, Release, Relaxed, guard);
        false
    } else {
        // looks like the actual tail; attempt to link in `n`
        let result = o
            .next
            .compare_exchange(Shared::null(), new, Release, Relaxed, guard)
            .is_ok();
        if result {
            // try to move the tail pointer forward
            let _ = self
                .tail
                .compare_exchange(onto, new, Release, Relaxed, guard);
        }
        result
    }
}

fn drop(&mut self) {
    if mem::needs_drop::<T>() {
        // Get the index of the head.
        let head = *self.head.get_mut();
        let tail = *self.tail.get_mut();

        let hix = head & (self.one_lap - 1);
        let tix = tail & (self.one_lap - 1);

        let len = if hix < tix {
            tix - hix
        } else if hix > tix {
            self.capacity() - hix + tix
        } else if tail == head {
            0
        } else {
            self.capacity()
        };

        // Loop over all slots that hold a message and drop them.
        for i in 0..len {
            // Compute the index of the next slot holding a message.
            let index = if hix + i < self.capacity() {
                hix + i
            } else {
                hix + i - self.capacity()
            };

            unsafe {
                debug_assert!(index < self.buffer.len());
                let slot = self.buffer.get_unchecked_mut(index);
                (*slot.value.get()).assume_init_drop();
            }
        }
    }
}

fn next(&mut self) -> Option<Self::Item> {
    let value = &mut self.value;
    let head = *value.head.get_mut();
    if value.head.get_mut() != value.tail.get_mut() {
        let index = head & (value.one_lap - 1);
        let lap = head & !(value.one_lap - 1);
        // SAFETY: We have mutable access to this, so we can read without
        // worrying about concurrency. Furthermore, we know this is
        // initialized because it is the value pointed at by `value.head`
        // and this is a non-empty queue.
        let val = unsafe {
            debug_assert!(index < value.buffer.len());
            let slot = value.buffer.get_unchecked_mut(index);
            slot.value.get().read().assume_init()
        };
        let new = if index + 1 < value.capacity() {
            // Same lap, incremented index.
            // Set to `{ lap: lap, index: index + 1 }`.
            head + 1
        } else {
            // One lap forward, index wraps around to zero.
            // Set to `{ lap: lap.wrapping_add(1), index: 0 }`.
            lap.wrapping_add(value.one_lap)
        };
        *value.head.get_mut() = new;
        Some(val)
    } else {
        None
    }
}

async fn analyze(
  &self,
  specifier: &ModuleSpecifier,
  source: Arc<str>,
  media_type: MediaType,
) -> Result<ModuleInfo, JsErrorBox> {
  // attempt to load from the cache
  let source_hash = CacheDBHash::from_hashable(&source);
  if let Some(info) =
    self.load_cached_module_info(specifier, media_type, source_hash)
  {
    return Ok(info);
  }

  // otherwise, get the module info from the parsed source cache
  let module_info = deno_core::unsync::spawn_blocking({
    let cache = self.parsed_source_cache.clone();
    let specifier = specifier.clone();
    move || {
      let parser = cache.as_capturing_parser();
      let analyzer = ParserModuleAnalyzer::new(&parser);
      analyzer
        .analyze_sync(&specifier, source, media_type)
        .map_err(JsErrorBox::from_err)
    }
  })
  .await
  .unwrap()?;

  // then attempt to cache it
  self.save_module_info_to_cache(
    specifier,
    media_type,
    source_hash,
    &module_info,
  );

  Ok(module_info)
}

pub fn tokens_within_range(
  tokens: &SemanticTokens,
  range: lsp::Range,
) -> SemanticTokens {
  let mut line = 0;
  let mut character = 0;

  let mut first_token_line = 0;
  let mut first_token_char = 0;
  let mut keep_start_idx = tokens.data.len();
  let mut keep_end_idx = keep_start_idx;
  for (i, token) in tokens.data.iter().enumerate() {
    if token.delta_line != 0 {
      character = 0;
    }
    line += token.delta_line;
    character += token.delta_start;
    let token_start = lsp::Position::new(line, character);
    if i < keep_start_idx && token_start >= range.start {
      keep_start_idx = i;
      first_token_line = line;
      first_token_char = character;
    }
    if token_start > range.end {
      keep_end_idx = i;
      break;
    }
  }
  if keep_end_idx == keep_start_idx {
    return SemanticTokens {
      result_id: None,
      data: Vec::new(),
    };
  }

  let mut data = tokens.data[keep_start_idx..keep_end_idx].to_vec();
  // we need to adjust the delta_line and delta_start on the first token
  // as it is relative to 0 now, not the previous token
  let first_token = &mut data[0];
  first_token.delta_line = first_token_line;
  first_token.delta_start = first_token_char;

  SemanticTokens {
    result_id: None,
    data,
  }
}

