fn pick_candidates(
  candidates: &[ScriptCandidate],
  existing_allowed: &mut HashSet<PackageReq>,
) -> Result<ChosenCandidates, AnyError> {
  if candidates.is_empty() {
    return Ok(ChosenCandidates {
      denied: candidates.iter().map(|c| c.req.clone()).collect(),
      ..Default::default()
    });
  }

  let selected = interactive_picker::select_items(
    "Select which packages to approve lifecycle scripts for (<space> to select, ↑/↓/j/k to navigate, a to select all, i to invert selection, enter to accept, <Ctrl-c> to cancel)",
    candidates,
    HashSet::new(),
    |_idx, is_selected, is_checked, candidate| {
      render_candidate(candidate, is_selected, is_checked)
    },
  )?;

  let Some(selected) = selected else {
    return Ok(ChosenCandidates::default());
  };

  let mut approvals = Vec::with_capacity(selected.len());
  let mut denials = Vec::with_capacity(candidates.len() - selected.len());
  for (idx, candidate) in candidates.iter().enumerate() {
    if selected.contains(&idx) {
      if existing_allowed.insert(candidate.req.clone()) {
        approvals.push(candidate.req.clone());
      }
    } else {
      denials.push(candidate.req.clone());
    }
  }

  Ok(ChosenCandidates {
    approved: approvals,
    denied: denials,
  })
}

pub async fn audit(
  flags: Arc<Flags>,
  audit_flags: AuditFlags,
) -> Result<i32, AnyError> {
  let factory = CliFactory::from_flags(flags.clone());
  let npm_resolver = factory.npm_resolver().await?;
  let npm_resolver = npm_resolver.as_managed().unwrap();
  let snapshot = npm_resolver.resolution().snapshot();

  let npm_url = &factory.npmrc()?.default_config.registry_url;
  let http_provider = HttpClientProvider::new(None, None);
  let http_client = http_provider
    .get_or_create()
    .context("Failed to create HTTP client")?;

  let use_socket = audit_flags.socket;
  let fix = audit_flags.fix;

  let result =
    npm::call_audits_api(audit_flags, npm_url, &snapshot, http_client).await?;

  if use_socket {
    socket_dev::call_firewall_api(
      &snapshot,
      http_provider.get_or_create().unwrap(),
    )
    .await?;
  }

  if fix && !result.fixable_actions.is_empty() {
    apply_fixes(&factory, flags, &result.fixable_actions).await?;
  }

  Ok(result.exit_code)
}

fn identify_cycle(
  current_name: &str,
  visited: &mut HashSet<String>,
  stack: &mut Vec<String>,
  packages: &HashMap<String, HashSet<String>>,
) -> Option<Vec<String>> {
  if !visited.insert(current_name.to_string()) {
    return None;
  }
  stack.push(current_name.to_string());

  // A dep may not be a key in `packages` (e.g. an external, non-workspace
  // dependency); such a node has no outgoing edges and cannot be part of a
  // cycle, so treat it as a leaf.
  if let Some(deps) = packages.get(current_name) {
    // Sort for deterministic cycle reporting.
    let mut deps = deps.iter().collect::<Vec<_>>();
    deps.sort();
    for dep in deps {
      if let Some(start) = stack.iter().position(|name| name == dep) {
        let mut cycle = stack[start..].to_vec();
        cycle.push(dep.to_string());
        return Some(cycle);
      }
      if let Some(cycle) = identify_cycle(dep, visited, stack, packages) {
        return Some(cycle);
      }
    }
  }

  stack.pop();
  None
}

pub fn register(&mut self, source_fd: FileDescriptionRef<dyn SourceFileDescription>) {
    let poll =
        self.poll.as_ref().expect("Blocking I/O should not be called with isolation enabled");

    let id = source_fd.id();
    let token = Token(id.to_usize());

    // All possible interests.
    // We only care about the readable and writable interests because those are the only
    // interests which are available on all platforms. Internally, mio also
    // registers an error interest.
    let interest = Interest::READABLE | Interest::WRITABLE;

    // Treat errors from registering as fatal. On UNIX hosts this can only
    // fail due to system resource errors (e.g. ENOMEM or ENOSPC) or when the source is already registered.
    source_fd
        .with_source(&mut |source| poll.registry().register(source, token, interest))
        .unwrap();

    let source = BlockingIoSource {
        fd: FileDescriptionRef::downgrade(&source_fd),
        blocked_threads: BTreeMap::default(),
    };

    self.sources
        .try_insert(id, source)
        .unwrap_or_else(|_| panic!("Source should not already be registered"));
}

fn remove_dump_var(file: &mut Vec<String>, path: &PathBuf) {
    let mut curr = 0;
    // ... try disabling `dump_vars` one by one, until only the necessary ones are left.
    while curr < file.len() {
        let Some(line) = file[curr..].iter().position(|line| line.contains("dump_var")) else {
            // No more `dump_var`s to remove - exit early.
            break;
        };
        // Make the line absolute again.
        let line = line + curr;
        let mut file_copy = file.clone();
        // Try removing 3 consecutive lines(the call, block end and block beginning). This effectively removes a `dump_var`.
        file_copy.remove(line);
        file_copy.remove(line);
        file_copy.remove(line);
        // Not cached - the execution result can change.
        let mut uncached = None;
        // Check if this reduction is valid.
        if test_reduction(&file_copy, path, &mut uncached) {
            println!("Reduced {path:?} by 3 lines `remove_dump_var`");
            *file = file_copy;
            curr = line;
        } else {
            curr = line + 1;
        }
    }
    save_reduction(file, path, "remove_dump_var");
}

fn find_best_leaf_obligation<'db>(
    infcx: &InferCtxt<'db>,
    obligation: &PredicateObligation<'db>,
    consider_ambiguities: bool,
) -> PredicateObligation<'db> {
    let obligation = infcx.resolve_vars_if_possible(obligation.clone());
    // FIXME: we use a probe here as the `BestObligation` visitor does not
    // check whether it uses candidates which get shadowed by where-bounds.
    //
    // We should probably fix the visitor to not do so instead, as this also
    // means the leaf obligation may be incorrect.
    let obligation = infcx
        .fudge_inference_if_ok(|| {
            infcx
                .visit_proof_tree(
                    obligation.as_goal(),
                    &mut BestObligation { obligation: obligation.clone(), consider_ambiguities },
                )
                .break_value()
                .ok_or(())
                // walk around the fact that the cause in `Obligation` is ignored by folders so that
                // we can properly fudge the infer vars in cause code.
                .map(|o| (o.cause, o))
        })
        .map(|(cause, o)| PredicateObligation { cause, ..o })
        .unwrap_or(obligation);
    deeply_normalize_for_diagnostics(infcx, obligation.param_env, obligation)
}

