pub fn instantiate_query_response_and_region_obligations<R>(
    &self,
    cause: &ObligationCause,
    param_env: ParamEnv<'db>,
    original_values: &OriginalQueryValues<'db>,
    query_response: &Canonical<'db, QueryResponse<'db, R>>,
) -> InferResult<'db, R>
where
    R: TypeFoldable<DbInterner<'db>>,
{
    let InferOk { value: result_args, obligations } =
        self.query_response_instantiation(cause, param_env, original_values, query_response)?;

    for predicate in &query_response.value.region_constraints.outlives {
        let predicate = instantiate_value(self.interner, &result_args, *predicate);
        self.register_outlives_constraint(predicate);
    }

    for assumption in &query_response.value.region_constraints.assumptions {
        let assumption = instantiate_value(self.interner, &result_args, *assumption);
        self.register_region_assumption(assumption);
    }

    let user_result: R =
        query_response
            .instantiate_projected(self.interner, &result_args, |q_r| q_r.value.clone());

    Ok(InferOk { value: user_result, obligations })
}

fn new_inner<R>(
    size: Size,
    align: Align,
    init: AllocInit,
    params: <Bytes as AllocBytes>::AllocParams,
    fail: impl FnOnce() -> R,
) -> Result<Self, R> {
    // We raise an error if we cannot create the allocation on the host.
    // This results in an error that can happen non-deterministically, since the memory
    // available to the compiler can change between runs. Normally queries are always
    // deterministic. However, we can be non-deterministic here because all uses of const
    // evaluation (including ConstProp!) will make compilation fail (via hard error
    // or OOM) upon encountering a `MemoryExhausted` error.
    let bytes = Bytes::zeroed(size, align, params).ok_or_else(fail)?;

    Ok(Allocation {
        bytes,
        provenance: ProvenanceMap::new(),
        init_mask: InitMask::new(
            size,
            match init {
                AllocInit::Uninit => false,
                AllocInit::Zero => true,
            },
        ),
        align,
        mutability: Mutability::Mut,
        extra: (),
    })
}

fn normalize_alias_term(
    &mut self,
    alias_term: I::Term,
    has_escaping: HasEscapingBoundVars,
) -> Result<I::Term, NoSolution> {
    let current_universe = self.infcx.universe();
    self.infcx.create_next_universe();

    let (normalized, ambig_goal) = (self.normalize)(alias_term)?;

    // Return ambiguous higher ranked alias as is, if
    //   - it contains escaping vars, and
    //   - the normalized term contains infer vars newly created
    //     in the normalization above.
    // The problem is that they may be resolved to types
    // referencing the temporary placeholders.
    //
    // We can normalize the ambiguous alias again after the binder is instantiated.
    if ambig_goal.is_some() && has_escaping == HasEscapingBoundVars::Yes {
        let mut visitor = MaxUniverse::new(self.infcx);
        normalized.visit_with(&mut visitor);
        let max_universe = visitor.max_universe();
        if current_universe.cannot_name(max_universe) {
            return Ok(alias_term);
        }
    }

    self.stalled_goals.extend(ambig_goal);
    Ok(normalized)
}

pub fn early_report_macro_deprecation(
    lint_buffer: &mut LintBuffer,
    depr: &Deprecation,
    suggestion_span: Span,
    node_id: NodeId,
    path: String,
) {
    if suggestion_span.in_derive_expansion() {
        return;
    }

    let is_in_effect = depr.is_in_effect();
    let suggestion = depr.suggestion;
    let note = depr.note.map(|ident| ident.name);
    let since_kind = deprecated_since_kind(is_in_effect, depr.since);
    lint_buffer.dyn_buffer_lint(
        deprecation_lint(is_in_effect),
        node_id,
        suggestion_span,
        move |dcx, level| {
            let sub = suggestion.map(|suggestion| DeprecationSuggestion {
                span: suggestion_span,
                kind: "macro".to_owned(),
                suggestion,
            });

            Deprecated { sub, kind: "macro".to_owned(), path, note, since_kind }
                .into_diag(dcx, level)
        },
    );
}

fn check_explanation_has_doctest(explanation: &str, err_code: &str) -> (bool, bool, bool, bool) {
    let mut found_code_example = false;
    let mut found_proper_doctest = false;

    let mut emit_ignore_warning = false;
    let mut no_longer_emitted = false;

    for line in explanation.lines() {
        let line = line.trim();

        if line.starts_with("```") {
            found_code_example = true;

            // Check for the `rustdoc` doctest headers.
            if line.contains("compile_fail") && line.contains(err_code) {
                found_proper_doctest = true;
            }

            if line.contains("ignore") {
                emit_ignore_warning = true;
                found_proper_doctest = true;
            }
        } else if line
            .starts_with("#### Note: this error code is no longer emitted by the compiler")
        {
            no_longer_emitted = true;
            found_code_example = true;
            found_proper_doctest = true;
        }
    }

    (found_code_example, found_proper_doctest, emit_ignore_warning, no_longer_emitted)
}

fn check_join_lines(
    #[rust_analyzer::rust_fixture] ra_fixture_before: &str,
    #[rust_analyzer::rust_fixture] ra_fixture_after: &str,
) {
    let config = JoinLinesConfig {
        join_else_if: true,
        remove_trailing_comma: true,
        unwrap_trivial_blocks: true,
        join_assignments: true,
    };

    let (before_cursor_pos, before) = extract_offset(ra_fixture_before);
    let file = SourceFile::parse(&before, span::Edition::CURRENT).ok().unwrap();

    let range = TextRange::empty(before_cursor_pos);
    let result = join_lines(&config, &file, range);

    let actual = {
        let mut actual = before;
        result.apply(&mut actual);
        actual
    };
    let actual_cursor_pos = result
        .apply_to_offset(before_cursor_pos)
        .expect("cursor position is affected by the edit");
    let actual = add_cursor(&actual, actual_cursor_pos);
    assert_eq_text!(ra_fixture_after, &actual);
}

pub fn instantiate_canonical_state<D, I, T>(
    delegate: &D,
    span: I::Span,
    param_env: I::ParamEnv,
    orig_values: &mut Vec<I::GenericArg>,
    state: inspect::CanonicalState<I, T>,
) -> T
where
    D: SolverDelegate<Interner = I>,
    I: Interner,
    T: TypeFoldable<I>,
{
    // In case any fresh inference variables have been created between `state`
    // and the previous instantiation, extend `orig_values` for it.
    orig_values.extend(
        state.value.var_values.var_values.as_slice()[orig_values.len()..]
            .iter()
            .map(|&arg| delegate.fresh_var_for_kind_with_span(arg, span)),
    );

    let instantiation =
        compute_query_response_instantiation_values(delegate, orig_values, &state, span);

    let inspect::State { var_values, data } = delegate.instantiate_canonical(state, instantiation);

    unify_query_var_values(delegate, param_env, orig_values, var_values, span);
    data
}

fn _finish(self) -> Client
    where
        M: Transform<DefaultConnector<ConnectorService<S, Io>>, ConnectRequest> + 'static,
        M::Transform: Service<ConnectRequest, Response = ConnectResponse, Error = SendRequestError>,
    {
        let mut connector = self.connector;

        if let Some(val) = self.max_http_version {
            connector = connector.max_http_version(val);
        };
        if let Some(val) = self.conn_window_size {
            connector = connector.initial_connection_window_size(val)
        };
        if let Some(val) = self.stream_window_size {
            connector = connector.initial_window_size(val)
        };
        if let Some(val) = self.local_address {
            connector = connector.local_address(val);
        }

        let connector = DefaultConnector::new(connector.finish());
        let connector = boxed::rc_service(self.middleware.new_transform(connector));

        Client(ClientConfig {
            default_headers: Rc::new(self.default_headers),
            timeout: self.timeout,
            connector,
        })
    }

async fn test_pool_lifetime() {
    let generated = Rc::new(Cell::new(0));
    let generated_clone = generated.clone();

    let connector = TestPoolConnector { generated };

    let config = ConnectorConfig {
        conn_lifetime: Duration::from_secs(1),
        ..Default::default()
    };

    let pool = super::ConnectionPool::new(connector, config);

    let req = Connect {
        uri: Uri::from_static("http://localhost"),
        addr: None,
    };

    let conn = pool.call(req.clone()).await.unwrap();
    assert_eq!(1, generated_clone.get());
    release(conn);

    let conn = pool.call(req.clone()).await.unwrap();
    assert_eq!(1, generated_clone.get());
    release(conn);

    actix_rt::time::sleep(Duration::from_millis(1500)).await;
    actix_rt::task::yield_now().await;

    let conn = pool.call(req).await.unwrap();
    // Note: spawned recycle connection is not ran yet.
    // This is tokio current thread runtime specific behavior.
    assert_eq!(2, generated_clone.get());

    // yield task so the old connection is properly dropped.
    actix_rt::task::yield_now().await;
    assert_eq!(1, generated_clone.get());

    release(conn);
}

fn build(&self, dent: ignore::DirEntry) -> Option<Haystack> {
    let hay = Haystack { dent, strip_dot_prefix: self.strip_dot_prefix };
    if let Some(err) = hay.dent.error() {
        ignore_message!("{err}");
    }
    // If this entry was explicitly provided by an end user, then we always
    // want to search it.
    if hay.is_explicit() {
        return Some(hay);
    }
    // At this point, we only want to search something if it's explicitly a
    // file. This omits symlinks. (If ripgrep was configured to follow
    // symlinks, then they have already been followed by the directory
    // traversal.)
    if hay.is_file() {
        return Some(hay);
    }
    // We got nothing. Emit a debug message, but only if this isn't a
    // directory. Otherwise, emitting messages for directories is just
    // noisy.
    if !hay.is_dir() {
        log::debug!(
            "ignoring {}: failed to pass haystack filter: \
             file type: {:?}, metadata: {:?}",
            hay.dent.path().display(),
            hay.dent.file_type(),
            hay.dent.metadata()
        );
    }
    None
}

fn filter_overlapping_text_changes(
  mut text_changes: Vec<deno_ast::TextChange>,
) -> Vec<deno_ast::TextChange> {
  let mut seen_imports = HashSet::new();
  text_changes.sort_by_key(|change| change.range.start);
  let mut filtered: Vec<deno_ast::TextChange> =
    Vec::with_capacity(text_changes.len());
  for change in text_changes.into_iter() {
    let overlaps_last = filtered
      .last()
      .map(|prev| change.range.start <= prev.range.end)
      .unwrap_or(false);
    let is_duplicate_import =
      change.new_text.trim_start().starts_with("import ")
        && seen_imports.contains(change.new_text.trim());

    if overlaps_last || is_duplicate_import {
      // skip this edit
      continue;
    }

    // remember any import we keep so we can drop later duplicates
    if change.new_text.trim_start().starts_with("import ") {
      seen_imports.insert(change.new_text.trim().to_owned());
    }

    filtered.push(change);
  }
  filtered
}

fn unfurl_wasm(
  &self,
  specifier: &Url,
  data: &[u8],
  diagnostics_collector: &PublishDiagnosticsCollector,
) -> Result<Vec<u8>, AnyError> {
  log::debug!("Unfurling {}", specifier);
  let mut reporter = |diagnostic| {
    diagnostics_collector
      .push(PublishDiagnostic::SpecifierUnfurl(diagnostic));
  };
  // Wasm modules are binary, so there is no source text to point diagnostics
  // at. Use an empty text info with a zeroed range so any diagnostics report
  // the referrer without a (meaningless) code frame.
  let text_info = SourceTextInfo::from_string(String::new());
  let zeroed_range = deno_graph::PositionRange::zeroed();
  super::wasm::unfurl_wasm(data, &mut |module_specifier| {
    self
      .specifier_unfurler
      .unfurl_specifier_reporting_diagnostic(
        specifier,
        module_specifier,
        ResolutionKind::Execution,
        &text_info,
        PositionOrSourceRangeRef::PositionRange(&zeroed_range),
        &mut reporter,
      )
  })
}

pub(crate) fn default_runtime(attributes: Attributes, input: Input) -> TokenStream {
  // create a new copy to manipulate for the wry feature flag
  let mut wry = input.clone();
  let wry_runtime = wry
    .last_param_mut()
    .expect("default_runtime requires the item to have at least 1 generic parameter");

  // set the default value of the last generic parameter to the provided runtime type
  match wry_runtime {
    GenericParam::Type(
      param @ TypeParam {
        eq_token: None,
        default: None,
        ..
      },
    ) => {
      param.eq_token = Some(parse_quote!(=));
      param.default = Some(attributes.default_type);
    }
    _ => {
      panic!("DefaultRuntime requires the last parameter to not have a default value")
    }
  };

  let feature = attributes.feature.to_string();

  quote!(
    #[cfg(feature = #feature)]
    #wry

    #[cfg(not(feature = #feature))]
    #input
  )
}
